class Playground {
    async run(inputs) {
        const nums = JSON.parse(inputs[0]);
        const target = parseInt(inputs[1]);

        this.arr.init(nums);
        this.vars.init([['left', 0], ['right', nums.length - 1], ['mid', -1], ['target', target]]);

        let left = 0;
        let right = nums.length - 1;

        while (left <= right) {
            let mid = Math.floor((left + right) / 2);
            this.vars.put('mid', mid);
            this.arr.highlight(mid, '#6c8cff');
            this.log(`Checking middle index ${mid} (value: ${nums[mid]})`);
            await this.await();

            if (nums[mid] === target) {
                this.log(`Found target at index ${mid}`);
                return mid;
            }

            // Left side is sorted
            if (nums[left] <= nums[mid]) {
                if (target >= nums[left] && target < nums[mid]) {
                    right = mid - 1;
                } else {
                    left = mid + 1;
                }
            } 
            // Right side is sorted
            else {
                if (target > nums[mid] && target <= nums[right]) {
                    left = mid + 1;
                } else {
                    right = mid - 1;
                }
            }

            this.vars.put('left', left);
            this.vars.put('right', right);
            this.arr.highlight(mid, '#ffffff');
            await this.await();
        }

        this.log('Target not found');
        return -1;
    }
}
